export type EstadoIPVAPCD = typeof estadosIPVAPCD[keyof typeof estadosIPVAPCD];

export const listaEstados = Object.entries(estadosIPVAPCD).map(([uf, dados]) => ({
  uf,
  nome: dados.nome
})).sort((a, b) => a.nome.localeCompare(b.nome));
